export KUBECONFIG=/mydata/karma/runs/error-prone-rerun/elasticsearch-scale-users-audit-20260618_123154/bundle/kubeconfig
read -r -d '' PATCH <<'EOF'
{
  "spec": {"template": {"spec": {
    "volumes": [
      {"name": "file-realm", "secret": {"secretName": "es-file-realm-aggregate",
        "items": [
          {"key": "users", "path": "users"},
          {"key": "users_roles", "path": "users_roles"},
          {"key": "roles.yml", "path": "roles.yml"}
        ]}}
    ],
    "containers": [{"name": "elasticsearch", "volumeMounts": [
      {"name": "file-realm", "mountPath": "/usr/share/elasticsearch/config/users", "subPath": "users", "readOnly": true},
      {"name": "file-realm", "mountPath": "/usr/share/elasticsearch/config/users_roles", "subPath": "users_roles", "readOnly": true},
      {"name": "file-realm", "mountPath": "/usr/share/elasticsearch/config/roles.yml", "subPath": "roles.yml", "readOnly": true}
    ]}]
  }}}
}
EOF
for s in es es-new; do
  echo "=== patch $s ==="
  kubectl -n elasticsearch patch sts $s --type=strategic -p "$PATCH"
done
